function recordStop() {
    if (!window.connectedDevice || !window.connectedDevice.ip) { showToast('warning', '请先在「设备管理」中连接设备'); return; }
    var deviceId = window.connectedDevice.ip;
    apiPost('/api/v1/ptz/' + deviceId + '/record/stop', null).then(function(result) {
        if (result && result.success) {
            showToast('success', '录像已停止');
            addLog('info', '录像已停止: ' + (result.message || ''));
            document.getElementById('btnRecordStart').disabled = false;
            document.getElementById('btnRecordStop').disabled = true;
            document.getElementById('recordStatusInfo').textContent = '状态: 未录制';
        } else {
            showToast('error', result ? result.message : '录像停止失败');
        }
    }).catch(function(e) {
        showToast('error', '录像异常: ' + e.message);
    });
}
function snapshotCapture() {
    if (!window.connectedDevice || !window.connectedDevice.ip) { showToast('warning', '请先在「设备管理」中连接设备'); return; }
    var deviceId = window.connectedDevice.ip;
    var btn = document.getElementById('btnSnapshot');
    btn.disabled = true;
    btn.textContent = '抓取中...';
    apiGet('/api/v1/streams/' + deviceId + '/snapshot').then(function(result) {
        btn.disabled = false;
        btn.textContent = '📸 抓取快照';
        if (result && result.success) {
            showToast('success', '快照抓取成功');
            addLog('success', result.message || '快照抓取成功');
            // Try to show snapshot using the data URL or preview URL
            if (result.data && result.data.preview_url) {
                // Open in new tab or show in preview
                var preview = document.getElementById('snapshotPreview');
                var img = document.getElementById('snapshotImg');
                if (preview && img) {
                    img.src = result.data.preview_url;
                    preview.style.display = 'block';
                }
            }
        } else {
            showToast('error', result ? result.message : '快照抓取失败');
        }
    }).catch(function(e) {
        btn.disabled = false;
        btn.textContent = '📸 抓取快照';
        showToast('error', '快照异常: ' + e.message);
    });
}
